```csharp
public enum Color
{
    Red,
    Green,
    Blue,
    Yellow,
    Purple
}

public static class ColorExtensions
{
    public static string GetHexCode(this Color color)
    {
        switch (color)
        {
            case Color.Red:
                return "#FF0000";
            case Color.Green:
                return "#00FF00";
            case Color.Blue:
                return "#0000FF";
            case Color.Yellow:
                return "#FFFF00";
            case Color.Purple:
                return "#FF00FF";
            default:
                throw new ArgumentException("Invalid color");
        }
    }
}
```

